 if(in_array($a,['delete_member','duplicate_member','toggle_member'],true)){$id=(int)$_POST['id'];$s=$pdo->prepare('SELECT * FROM team_members WHERE id=:id');$s->execute([':id'=>$id]);$r=$s->fetch();if(!$r)throw new RuntimeException('Member not found.');if($a==='delete_member'){$pdo->prepare('DELETE FROM team_members WHERE id=:id')->execute([':id'=>$id]);if(tmImg((string)$r['image'])&&is_file(dirname(__DIR__).'/'.$r['image']))unlink(dirname(__DIR__).'/'.$r['image']);}elseif($a==='toggle_member')$pdo->prepare('UPDATE team_members SET status=CASE status WHEN 1 THEN 0 ELSE 1 END,updated_at=CURRENT_TIMESTAMP WHERE id=:id')->execute([':id'=>$id]);else{$slug=$r['slug'].'-copy-'.time();$pdo->prepare('INSERT INTO team_members(full_name,slug,designation,department,team_group_id,short_bio,full_bio,email,phone,image,image_alt,featured_member,status,display_order)VALUES(:n,:s,:d,:dep,:g,:sb,:fb,:e,:p,\'\',:alt,0,0,:sort)')->execute([':n'=>$r['full_name'].' Copy',':s'=>$slug,':d'=>$r['designation'],':dep'=>$r['department'],':g'=>$r['team_group_id'],':sb'=>$r['short_bio'],':fb'=>$r['full_bio'],':e'=>'',':p'=>'',':alt'=>$r['image_alt'],':sort'=>$r['display_order']]);}tmFlash('Member action completed.');header('Location:team-management.php');exit;}
