<style>.team-stats{display:grid;grid-template-columns:repeat(5,1fr);gap:12px;margin:22px 0}.team-stat{padding:18px;border:1px solid var(--line);border-radius:7px;background:#fff}.team-stat strong{display:block;color:var(--green);font-size:1.7rem}.team-toolbar,.team-filters,.bulk-bar{display:flex;gap:10px;flex-wrap:wrap;margin:18px 0}.team-toolbar a,.team-toolbar button{display:inline-flex;min-height:44px;padding:0 14px;align-items:center;border:1px solid var(--green);border-radius:4px;background:var(--green);color:#fff;text-decoration:none}.team-filters input,.team-filters select,.bulk-bar select{min-height:44px;padding:8px;border:1px solid #aebcb6;border-radius:4px}.team-table-wrap{overflow-x:auto}.team-table{width:100%;border-collapse:collapse;min-width:1000px}.team-table th,.team-table td{padding:11px;border-bottom:1px solid var(--line);text-align:left;font-size:.82rem}.table-photo{width:46px;height:56px;object-fit:cover;border-radius:4px;background:#e5ece8}.table-placeholder{display:grid;place-items:center;color:var(--green)}.status-pill{padding:4px 8px;border-radius:15px;background:#e5f2ed}.team-group-cards{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.team-group-card{padding:16px;border:1px solid var(--line);border-radius:7px}.team-admin-editor{position:fixed;top:0;right:0;z-index:100;width:min(560px,100%);height:100vh;overflow:auto;padding:28px;background:#fff;box-shadow:-15px 0 40px rgba(0,0,0,.18)}.editor-actions{position:sticky;bottom:0;display:flex;gap:10px;padding:15px 0;background:#fff}.pagination{display:flex;gap:6px;margin-top:18px}.pagination a{padding:7px 10px;border:1px solid var(--line)}@media(max-width:900px){.team-stats{grid-template-columns:repeat(2,1fr)}.team-group-cards{grid-template-columns:1fr}.admin-main{width:calc(100% - 20px)}.team-admin-editor{width:100%}}</style>
